sql:
SELECT coverage_percentage
FROM coverage_metrics
WHERE class_name = 'CompanyService' AND version_id = 0;

SELECT AVG(CAST(REPLACE(coverage_percentage, '%', '') AS REAL)) AS average_coverage_percentage
FROM coverage_metrics
WHERE class_name = 'CompanyService';

external_knowledge:
; A package is considered a top-level package if it is not nested within another package (i.e., its group_id is NULL); 
; The coverage percentage signifies the extent to which the code within a class has been tested; 
; Valid accesses refer to instances where a user has successfully viewed or downloaded coverage metrics for a class.

